import type { ElaEvent, EventsDataset } from "./types";
import { SCHEMA_VERSION } from "./types";

/**
 * Defensive loading + freshness helpers for the committed events dataset.
 *
 * The dataset is (re)generated by the scraper and committed to the repo; the
 * frontend must never crash on a partial, stale, or malformed file. These
 * helpers validate the shape, drop unusable events, and expose data-age info
 * so the UI can warn when the data is old.
 */

export type DatasetStatus = "ok" | "empty" | "invalid";

export interface LoadedDataset {
  dataset: EventsDataset;
  status: DatasetStatus;
}

const EMPTY_DATASET: EventsDataset = {
  generatedAt: "",
  schemaVersion: SCHEMA_VERSION,
  regionIds: [],
  events: [],
};

/** Validate and normalize an unknown value into a safe EventsDataset. */
export function safeLoadDataset(raw: unknown): LoadedDataset {
  if (!raw || typeof raw !== "object") {
    return { dataset: EMPTY_DATASET, status: "invalid" };
  }
  const d = raw as Partial<EventsDataset>;
  if (
    !Array.isArray(d.events) ||
    typeof d.generatedAt !== "string" ||
    d.schemaVersion !== SCHEMA_VERSION
  ) {
    return { dataset: EMPTY_DATASET, status: "invalid" };
  }

  const events = d.events.filter(isValidEvent);
  const dataset: EventsDataset = {
    generatedAt: d.generatedAt,
    schemaVersion: d.schemaVersion,
    regionIds: Array.isArray(d.regionIds) ? d.regionIds : [],
    events,
  };
  return { dataset, status: events.length > 0 ? "ok" : "empty" };
}

/** Minimal structural check so a bad record can't crash the map/list. */
export function isValidEvent(e: unknown): e is ElaEvent {
  if (!e || typeof e !== "object") return false;
  const ev = e as Record<string, unknown>;
  const loc = ev.location as Record<string, unknown> | undefined;
  return (
    typeof ev.id === "string" &&
    typeof ev.title === "string" &&
    ev.title.length > 0 &&
    typeof ev.startsAt === "string" &&
    !!loc &&
    typeof loc.lat === "number" &&
    typeof loc.lng === "number" &&
    Array.isArray(ev.ageBands) &&
    typeof ev.category === "string"
  );
}

const MS_PER_HOUR = 3_600_000;

/** Age of the dataset in hours, or null when the timestamp is unusable. */
export function dataAgeHours(generatedAt: string, now: number = Date.now()): number | null {
  const t = Date.parse(generatedAt);
  if (Number.isNaN(t)) return null;
  return (now - t) / MS_PER_HOUR;
}

/** True when the dataset is older than `maxAgeHours` (default 48h). */
export function isStale(
  generatedAt: string,
  maxAgeHours = 48,
  now: number = Date.now()
): boolean {
  const hours = dataAgeHours(generatedAt, now);
  return hours === null ? false : hours > maxAgeHours;
}

/** Human "3 days ago" style label for the dataset age. */
export function formatAge(generatedAt: string, now: number = Date.now()): string {
  const hours = dataAgeHours(generatedAt, now);
  if (hours === null) return "an unknown time ago";
  if (hours < 0) return "just now";
  if (hours < 1) return "less than an hour ago";
  if (hours < 24) {
    const n = Math.round(hours);
    return `${n} hour${n === 1 ? "" : "s"} ago`;
  }
  const days = Math.round(hours / 24);
  return `${days} day${days === 1 ? "" : "s"} ago`;
}
